//! Integration tests for HybridPipeline (Jamba + Falcon-H1).
//!
//! Uses tiny synthetic dimensions so tests run in-process with no I/O.

use distributed_inference::loader::{KnotConfig, OwnedBytes, WeightBackend};
use distributed_inference::model_hybrid::{HybridConfig, HybridPipeline};
use std::any::Any;
use std::collections::HashMap;
use std::sync::Arc;

// ─────────────────────────────────────────────────────────────────────────────
// Mock backend
// ─────────────────────────────────────────────────────────────────────────────

struct MockBackend {
    store: HashMap<String, Vec<u8>>,
}

impl MockBackend {
    fn new() -> Self {
        Self {
            store: HashMap::new(),
        }
    }

    fn insert_f32(&mut self, name: &str, v: Vec<f32>) {
        let bytes: Vec<u8> = v.iter().flat_map(|f| f.to_le_bytes()).collect();
        self.store.insert(name.to_string(), bytes.clone());
        self.store.insert(format!("{name}.bin"), bytes);
    }

    fn fill(&mut self, name: &str, n: usize, seed: f32) {
        let v: Vec<f32> = (0..n).map(|i| (i as f32 * seed).sin() * 0.05).collect();
        self.insert_f32(name, v);
    }

    fn fill_ones(&mut self, name: &str, n: usize) {
        self.insert_f32(name, vec![1.0f32; n]);
    }

    fn into_arc(self) -> Arc<dyn WeightBackend> {
        Arc::new(self)
    }
}

unsafe impl Send for MockBackend {}
unsafe impl Sync for MockBackend {}

impl WeightBackend for MockBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        let key = if self.store.contains_key(name) {
            name.to_string()
        } else if self.store.contains_key(bare) {
            bare.to_string()
        } else {
            return Err(format!("MockBackend: missing {name:?}"));
        };
        Ok(OwnedBytes::Owned(Arc::new(self.store[&key].clone())))
    }

    fn has_tensor(&self, name: &str) -> bool {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store.contains_key(name) || self.store.contains_key(bare)
    }

    fn as_any(&self) -> &dyn Any {
        self
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Test dimensions
// ─────────────────────────────────────────────────────────────────────────────

const D: usize = 32; // hidden_dim
const N_H: usize = 4; // n_heads
const KV_H: usize = 2; // n_kv_heads
const HD: usize = 8; // head_dim  (D / N_H)
const FFN: usize = 64; // intermediate_size
const DS: usize = 4; // d_state
const DC: usize = 4; // d_conv
const DI: usize = 64; // d_inner = D * 2
const VOCAB: usize = 32;

// Jamba-style: 8 layers, attention every 8th → only layer 7 is attention
const JAMBA_LAYERS: usize = 8;
const JAMBA_PERIOD: usize = 8;

// Falcon-H1-style: 4 layers, alternating → layers 1 and 3 are attention
const FH1_LAYERS: usize = 4;
const FH1_PERIOD: usize = 2;

fn jamba_knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {JAMBA_LAYERS},
        "num_heads": {N_H}, "num_kv_heads": {KV_H}, "head_dim": {HD},
        "intermediate_size": {FFN}, "vocab_size": {VOCAB},
        "arch": "jamba",
        "d_state": {DS}, "d_conv": {DC}, "ssm_expand": 2,
        "hybrid_attn_layer_period": {JAMBA_PERIOD},
        "max_seq_len": 64,
        "rope_theta": 10000.0
    }}"#
    ))
    .unwrap()
}

fn falcon_h1_knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {FH1_LAYERS},
        "num_heads": {N_H}, "num_kv_heads": {KV_H}, "head_dim": {HD},
        "intermediate_size": {FFN}, "vocab_size": {VOCAB},
        "arch": "falcon-h1",
        "d_state": {DS}, "d_conv": {DC}, "ssm_expand": 2,
        "hybrid_attn_layer_period": {FH1_PERIOD},
        "max_seq_len": 64,
        "rope_theta": 10000.0
    }}"#
    ))
    .unwrap()
}

fn build_backend(num_layers: usize, attn_period: usize) -> MockBackend {
    let mut b = MockBackend::new();

    b.fill("token_embd_weight", VOCAB * D, 0.01);
    b.fill_ones("output_norm_weight", D);
    b.fill("output_weight", VOCAB * D, 0.02);

    for l in 0..num_layers {
        let n = |s: &str| format!("blk_{l}_{s}");
        let is_attn = (l + 1) % attn_period == 0;

        b.fill_ones(&n("input_norm_weight"), D);
        b.fill_ones(&n("ffn_norm_weight"), D);
        b.fill(&n("ffn_gate_weight"), FFN * D, 0.02);
        b.fill(&n("ffn_up_weight"), FFN * D, 0.02);
        b.fill(&n("ffn_down_weight"), D * FFN, 0.02);

        if is_attn {
            b.fill(&n("attn_q_weight"), N_H * HD * D, 0.03);
            b.fill(&n("attn_k_weight"), KV_H * HD * D, 0.03);
            b.fill(&n("attn_v_weight"), KV_H * HD * D, 0.03);
            b.fill(&n("attn_o_weight"), D * N_H * HD, 0.03);
        } else {
            b.fill(&n("ssm_in_proj_weight"), DI * 2 * D, 0.03);
            b.fill(&n("ssm_conv1d_weight"), DC * DI, 0.02);
            b.insert_f32(&n("ssm_conv1d_bias"), vec![0.0f32; DI]);
            b.fill(&n("ssm_a_log"), DS, -0.5);
            b.insert_f32(&n("ssm_dt_bias"), vec![0.1f32; DI]);
            b.fill_ones(&n("ssm_d"), DI);
            b.fill(&n("ssm_out_proj_weight"), D * DI, 0.02);
        }
    }
    b
}

// ─────────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────────

#[test]
fn hybrid_config_from_knot_jamba() {
    let cfg = HybridConfig::from_knot(&jamba_knot_config());
    assert_eq!(cfg.arch, "jamba");
    assert_eq!(cfg.hidden_dim, D);
    assert_eq!(cfg.num_layers, JAMBA_LAYERS);
    assert_eq!(cfg.attn_layer_period, JAMBA_PERIOD);
    assert_eq!(cfg.d_state, DS);
    assert_eq!(cfg.d_inner, DI);
    // Only layer 7 is attention
    assert!(cfg.is_attn_layer(7));
    assert!(!cfg.is_attn_layer(0));
    assert!(!cfg.is_attn_layer(3));
}

#[test]
fn hybrid_config_from_knot_falcon_h1() {
    let cfg = HybridConfig::from_knot(&falcon_h1_knot_config());
    assert_eq!(cfg.arch, "falcon-h1");
    assert_eq!(cfg.attn_layer_period, FH1_PERIOD);
    // Layers 1 and 3 are attention
    assert!(cfg.is_attn_layer(1));
    assert!(cfg.is_attn_layer(3));
    assert!(!cfg.is_attn_layer(0));
    assert!(!cfg.is_attn_layer(2));
}

#[test]
fn knot_config_hybrid_fields_roundtrip() {
    let json = r#"{
        "hidden_dim": 4096, "num_layers": 32, "num_heads": 32, "num_kv_heads": 8,
        "head_dim": 128, "intermediate_size": 14336, "vocab_size": 65536,
        "arch": "jamba",
        "d_state": 128, "d_conv": 4, "ssm_expand": 2,
        "hybrid_attn_layer_period": 8, "max_seq_len": 262144
    }"#;
    let cfg: KnotConfig = serde_json::from_str(json).unwrap();
    assert_eq!(cfg.arch, "jamba");
    assert_eq!(cfg.hybrid_attn_layer_period, Some(8));
    assert_eq!(cfg.max_seq_len, Some(262144));
    assert_eq!(cfg.d_state, Some(128));
    assert_eq!(cfg.rwkv_n_heads, None);
}

#[test]
fn jamba_pipeline_forward_produces_finite_logits() {
    let cfg = jamba_knot_config();
    let backend = build_backend(JAMBA_LAYERS, JAMBA_PERIOD).into_arc();
    let mut pipeline = HybridPipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut logits);

    assert_eq!(logits.len(), VOCAB);
    assert!(
        logits.iter().all(|v| v.is_finite()),
        "Jamba logits contain NaN/Inf"
    );
}

#[test]
fn falcon_h1_pipeline_forward_produces_finite_logits() {
    let cfg = falcon_h1_knot_config();
    let backend = build_backend(FH1_LAYERS, FH1_PERIOD).into_arc();
    let mut pipeline = HybridPipeline::from_knot(&cfg, backend);

    let mut logits = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut logits);

    assert_eq!(logits.len(), VOCAB);
    assert!(
        logits.iter().all(|v| v.is_finite()),
        "Falcon-H1 logits contain NaN/Inf"
    );
}

#[test]
fn hybrid_pipeline_state_changes_across_tokens() {
    let cfg = falcon_h1_knot_config();
    let backend = build_backend(FH1_LAYERS, FH1_PERIOD).into_arc();
    let mut pipeline = HybridPipeline::from_knot(&cfg, backend);

    let mut l0 = vec![0.0f32; VOCAB];
    let mut l1 = vec![0.0f32; VOCAB];
    pipeline.forward_one(0, &mut l0);
    pipeline.forward_one(5, &mut l1);

    let changed = l0.iter().zip(&l1).any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(
        changed,
        "Hybrid logits identical across tokens — state not updating"
    );
}

#[test]
fn hybrid_pipeline_reset_reproduces_first_output() {
    let cfg = falcon_h1_knot_config();
    let backend = build_backend(FH1_LAYERS, FH1_PERIOD).into_arc();
    let mut pipeline = HybridPipeline::from_knot(&cfg, backend);

    let mut out_first = vec![0.0f32; VOCAB];
    let mut out_mid = vec![0.0f32; VOCAB];
    let mut out_reset = vec![0.0f32; VOCAB];

    pipeline.forward_one(0, &mut out_first);
    pipeline.forward_one(3, &mut out_mid);
    pipeline.reset_states();
    pipeline.forward_one(0, &mut out_reset);

    for (a, b) in out_first.iter().zip(&out_reset) {
        assert!((a - b).abs() < 1e-5, "reset+replay mismatch: {a} vs {b}");
    }
    let mid_differs = out_first
        .iter()
        .zip(&out_mid)
        .any(|(a, b)| (a - b).abs() > 1e-6);
    assert!(mid_differs, "Mid-run output should differ from first");
}
